-- ============================================================
-- DigiMerchant BackOffice - Oracle Auth/RBAC/Audit Schema V2
-- Prefix: DMBO_
-- Design style: tham khảo mô hình BO_FUNCTION / BO_ROLE / BO_ROLE_FUNC /
--               BO_USER / BO_USER_HISTORIES hiện có.
--
-- Important:
--   1) Run this script with the target Oracle schema user.
--   2) Do NOT store plain passwords. PASSWORD_HASH must be generated by .NET.
--   3) This script does NOT include database connection credentials.
--   4) If you already ran V1 schema with DMBO_USERS/DMBO_ROLES/DMBO_PERMISSIONS,
--      do not run both models together unless you intentionally keep both.
-- ============================================================

-- ============================================================
-- 1. DMBO_FUNCTION
--    Lưu menu, màn hình, button/action/API permission.
--    FUNCTION_DISPLAY = 1: hiển thị menu
--    FUNCTION_DISPLAY = 0: quyền thao tác/API/action ẩn
-- ============================================================
CREATE TABLE DMBO_FUNCTION (
    FUNCTION_ID       NUMBER(19)      NOT NULL,
    FUNCTION_CODE     VARCHAR2(150)   NOT NULL,
    FUNCTION_NAME     NVARCHAR2(255)  NOT NULL,
    FUNCTION_LEVEL    NUMBER(5)       DEFAULT 1 NOT NULL,
    FUNCTION_URL      VARCHAR2(500),
    FUNCTION_ORDER    NUMBER(10)      DEFAULT 0 NOT NULL,
    PARENT_ID         NUMBER(19),
    FUNCTION_DISPLAY  NUMBER(1)       DEFAULT 1 NOT NULL,
    STATUS            VARCHAR2(20)    DEFAULT 'ACTIVE' NOT NULL,

    CREATED_BY        VARCHAR2(100),
    CREATE_TIME       TIMESTAMP(6)    DEFAULT SYSTIMESTAMP NOT NULL,
    UPDATED_BY        VARCHAR2(100),
    UPDATE_TIME       TIMESTAMP(6),

    CONSTRAINT PK_DMBO_FUNCTION PRIMARY KEY (FUNCTION_ID),
    CONSTRAINT CK_DMBO_FUNCTION_DISPLAY CHECK (FUNCTION_DISPLAY IN (0, 1)),
    CONSTRAINT CK_DMBO_FUNCTION_STATUS CHECK (STATUS IN ('ACTIVE', 'INACTIVE')),
    CONSTRAINT FK_DMBO_FUNCTION_PARENT FOREIGN KEY (PARENT_ID) REFERENCES DMBO_FUNCTION(FUNCTION_ID)
);

CREATE SEQUENCE SEQ_DMBO_FUNCTION START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_FUNCTION_BI
BEFORE INSERT ON DMBO_FUNCTION
FOR EACH ROW
BEGIN
    IF :NEW.FUNCTION_ID IS NULL THEN
        SELECT SEQ_DMBO_FUNCTION.NEXTVAL INTO :NEW.FUNCTION_ID FROM DUAL;
    END IF;

    IF :NEW.CREATE_TIME IS NULL THEN
        :NEW.CREATE_TIME := SYSTIMESTAMP;
    END IF;
END;
/

CREATE UNIQUE INDEX UX_DMBO_FUNCTION_CODE ON DMBO_FUNCTION (UPPER(FUNCTION_CODE));
CREATE INDEX IX_DMBO_FUNCTION_PARENT ON DMBO_FUNCTION (PARENT_ID);
CREATE INDEX IX_DMBO_FUNCTION_STATUS ON DMBO_FUNCTION (STATUS);
CREATE INDEX IX_DMBO_FUNCTION_DISPLAY_ORDER ON DMBO_FUNCTION (FUNCTION_DISPLAY, FUNCTION_ORDER);


-- ============================================================
-- 2. DMBO_ROLE
-- ============================================================
CREATE TABLE DMBO_ROLE (
    ROLE_ID       NUMBER(19)      NOT NULL,
    ROLE_CODE     VARCHAR2(100)   NOT NULL,
    ROLE_NAME     NVARCHAR2(255)  NOT NULL,
    DESCRIPTION   NVARCHAR2(500),
    STATUS        VARCHAR2(20)    DEFAULT 'ACTIVE' NOT NULL,
    ROLE_LEVEL    NUMBER(5)       DEFAULT 99 NOT NULL,

    CREATED_BY    VARCHAR2(100),
    CREATE_TIME   TIMESTAMP(6)    DEFAULT SYSTIMESTAMP NOT NULL,
    UPDATED_BY    VARCHAR2(100),
    UPDATE_TIME   TIMESTAMP(6),

    CONSTRAINT PK_DMBO_ROLE PRIMARY KEY (ROLE_ID),
    CONSTRAINT CK_DMBO_ROLE_STATUS CHECK (STATUS IN ('ACTIVE', 'INACTIVE'))
);

CREATE SEQUENCE SEQ_DMBO_ROLE START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_ROLE_BI
BEFORE INSERT ON DMBO_ROLE
FOR EACH ROW
BEGIN
    IF :NEW.ROLE_ID IS NULL THEN
        SELECT SEQ_DMBO_ROLE.NEXTVAL INTO :NEW.ROLE_ID FROM DUAL;
    END IF;

    IF :NEW.CREATE_TIME IS NULL THEN
        :NEW.CREATE_TIME := SYSTIMESTAMP;
    END IF;
END;
/

CREATE UNIQUE INDEX UX_DMBO_ROLE_CODE ON DMBO_ROLE (UPPER(ROLE_CODE));
CREATE INDEX IX_DMBO_ROLE_STATUS ON DMBO_ROLE (STATUS);
CREATE INDEX IX_DMBO_ROLE_LEVEL ON DMBO_ROLE (ROLE_LEVEL);

COMMENT ON COLUMN DMBO_ROLE.ROLE_LEVEL IS '0=cao nhất (SUPER_ADMIN), số càng lớn quyền càng thấp';


-- ============================================================
-- 3. DMBO_ROLE_FUNC
--    Mapping role -> function/permission.
-- ============================================================
CREATE TABLE DMBO_ROLE_FUNC (
    ID             NUMBER(19)     NOT NULL,
    FUNCTION_ID    NUMBER(19)     NOT NULL,
    ROLE_ID        NUMBER(19)     NOT NULL,
    CREATE_TIME    TIMESTAMP(6)   DEFAULT SYSTIMESTAMP NOT NULL,
    CREATE_USER    VARCHAR2(100),

    CONSTRAINT PK_DMBO_ROLE_FUNC PRIMARY KEY (ID),
    CONSTRAINT FK_DMBO_ROLE_FUNC_FUNCTION FOREIGN KEY (FUNCTION_ID) REFERENCES DMBO_FUNCTION(FUNCTION_ID),
    CONSTRAINT FK_DMBO_ROLE_FUNC_ROLE FOREIGN KEY (ROLE_ID) REFERENCES DMBO_ROLE(ROLE_ID)
);

CREATE SEQUENCE SEQ_DMBO_ROLE_FUNC START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_ROLE_FUNC_BI
BEFORE INSERT ON DMBO_ROLE_FUNC
FOR EACH ROW
BEGIN
    IF :NEW.ID IS NULL THEN
        SELECT SEQ_DMBO_ROLE_FUNC.NEXTVAL INTO :NEW.ID FROM DUAL;
    END IF;

    IF :NEW.CREATE_TIME IS NULL THEN
        :NEW.CREATE_TIME := SYSTIMESTAMP;
    END IF;
END;
/

CREATE UNIQUE INDEX UX_DMBO_ROLE_FUNC_ROLE_FUNCTION ON DMBO_ROLE_FUNC (ROLE_ID, FUNCTION_ID);
CREATE INDEX IX_DMBO_ROLE_FUNC_FUNCTION_ID ON DMBO_ROLE_FUNC (FUNCTION_ID);


-- ============================================================
-- 4. DMBO_USER
--    Theo mô hình hiện có: mỗi user gắn 1 ROLE_ID.
--    Nếu sau này cần multi-role, có thể tách thêm DMBO_USER_ROLE.
-- ============================================================
CREATE TABLE DMBO_USER (
    USER_ID                  NUMBER(19)      NOT NULL,
    USER_NAME                VARCHAR2(100)   NOT NULL,
    FULL_NAME                NVARCHAR2(255),
    EMAIL                    VARCHAR2(255),
    PHONE                    VARCHAR2(50),

    STATUS                   NUMBER(1)       DEFAULT 1 NOT NULL,
    PASSWORD_HASH            VARCHAR2(500)   NOT NULL,
    PWD_EXPIRE_DATE          TIMESTAMP(6),
    ROLE_ID                  NUMBER(19)      NOT NULL,
    UUID                     VARCHAR2(100),

    NUMBER_OF_FAILED_LOGINS  NUMBER(10)      DEFAULT 0 NOT NULL,
    LAST_LOGIN_TIME          TIMESTAMP(6),
    LOCKOUT_END_AT           TIMESTAMP(6),
    IS_PASSWORD_CHANGED      NUMBER(1)       DEFAULT 0 NOT NULL,

    CREATED_DATE             TIMESTAMP(6)    DEFAULT SYSTIMESTAMP NOT NULL,
    CREATED_USER             VARCHAR2(100),
    UPDATED_DATE             TIMESTAMP(6),
    UPDATED_USER             VARCHAR2(100),

    CONSTRAINT PK_DMBO_USER PRIMARY KEY (USER_ID),
    CONSTRAINT FK_DMBO_USER_ROLE FOREIGN KEY (ROLE_ID) REFERENCES DMBO_ROLE(ROLE_ID),
    CONSTRAINT CK_DMBO_USER_STATUS CHECK (STATUS IN (0, 1, 2)),
    CONSTRAINT CK_DMBO_USER_IS_PWD_CHANGED CHECK (IS_PASSWORD_CHANGED IN (0, 1))
);

COMMENT ON COLUMN DMBO_USER.STATUS IS '0=INACTIVE, 1=ACTIVE, 2=LOCKED';

CREATE SEQUENCE SEQ_DMBO_USER START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_USER_BI
BEFORE INSERT ON DMBO_USER
FOR EACH ROW
BEGIN
    IF :NEW.USER_ID IS NULL THEN
        SELECT SEQ_DMBO_USER.NEXTVAL INTO :NEW.USER_ID FROM DUAL;
    END IF;

    IF :NEW.CREATED_DATE IS NULL THEN
        :NEW.CREATED_DATE := SYSTIMESTAMP;
    END IF;
END;
/

CREATE UNIQUE INDEX UX_DMBO_USER_USER_NAME ON DMBO_USER (UPPER(USER_NAME));
CREATE INDEX IX_DMBO_USER_ROLE_ID ON DMBO_USER (ROLE_ID);
CREATE INDEX IX_DMBO_USER_STATUS ON DMBO_USER (STATUS);
CREATE INDEX IX_DMBO_USER_LAST_LOGIN ON DMBO_USER (LAST_LOGIN_TIME);


-- ============================================================
-- 5. DMBO_REFRESH_TOKEN
--    Lưu refresh token dạng hash, không lưu token raw.
-- ============================================================
CREATE TABLE DMBO_REFRESH_TOKEN (
    ID                      NUMBER(19)      NOT NULL,
    USER_ID                 NUMBER(19)      NOT NULL,
    TOKEN_HASH              VARCHAR2(500)   NOT NULL,
    JWT_ID                  VARCHAR2(100),

    IP_ADDRESS              VARCHAR2(100),
    USER_AGENT              NVARCHAR2(500),

    EXPIRES_AT              TIMESTAMP(6)    NOT NULL,
    REVOKED_AT              TIMESTAMP(6),
    REPLACED_BY_TOKEN_HASH  VARCHAR2(500),

    CREATED_AT              TIMESTAMP(6)    DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_DMBO_REFRESH_TOKEN PRIMARY KEY (ID),
    CONSTRAINT FK_DMBO_REFRESH_TOKEN_USER FOREIGN KEY (USER_ID) REFERENCES DMBO_USER(USER_ID)
);

CREATE SEQUENCE SEQ_DMBO_REFRESH_TOKEN START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_REFRESH_TOKEN_BI
BEFORE INSERT ON DMBO_REFRESH_TOKEN
FOR EACH ROW
BEGIN
    IF :NEW.ID IS NULL THEN
        SELECT SEQ_DMBO_REFRESH_TOKEN.NEXTVAL INTO :NEW.ID FROM DUAL;
    END IF;

    IF :NEW.CREATED_AT IS NULL THEN
        :NEW.CREATED_AT := SYSTIMESTAMP;
    END IF;
END;
/

CREATE INDEX IX_DMBO_REFRESH_TOKEN_USER_ID ON DMBO_REFRESH_TOKEN (USER_ID);
CREATE INDEX IX_DMBO_REFRESH_TOKEN_EXPIRES_AT ON DMBO_REFRESH_TOKEN (EXPIRES_AT);
CREATE INDEX IX_DMBO_REFRESH_TOKEN_JWT_ID ON DMBO_REFRESH_TOKEN (JWT_ID);


-- ============================================================
-- 6. DMBO_USER_HISTORIES
--    Log user thực hiện tính năng nào, thao tác gì, đổi dữ liệu gì.
-- ============================================================
CREATE TABLE DMBO_USER_HISTORIES (
    HISTORY_ID    NUMBER(19)      NOT NULL,

    USER_ID       NUMBER(19),
    USER_NAME     VARCHAR2(100),
    FUNCTION_ID   NUMBER(19),
    FUNC_NAME     NVARCHAR2(255),

    ACTION_TYPE   VARCHAR2(100)   NOT NULL,
    ACTION_DESC   NVARCHAR2(1000),
    ACTION_DATE   TIMESTAMP(6)    DEFAULT SYSTIMESTAMP NOT NULL,

    EDIT_TABLE    VARCHAR2(100),
    OLD_VALUE     CLOB,
    NEW_VALUE     CLOB,

    IP_ADDRESS    VARCHAR2(100),
    USER_AGENT    NVARCHAR2(500),

    CONSTRAINT PK_DMBO_USER_HISTORIES PRIMARY KEY (HISTORY_ID),
    CONSTRAINT FK_DMBO_USER_HIS_USER FOREIGN KEY (USER_ID) REFERENCES DMBO_USER(USER_ID),
    CONSTRAINT FK_DMBO_USER_HIS_FUNCTION FOREIGN KEY (FUNCTION_ID) REFERENCES DMBO_FUNCTION(FUNCTION_ID)
);

CREATE SEQUENCE SEQ_DMBO_USER_HISTORIES START WITH 1 INCREMENT BY 1 NOCACHE NOCYCLE;

CREATE OR REPLACE TRIGGER TRG_DMBO_USER_HISTORIES_BI
BEFORE INSERT ON DMBO_USER_HISTORIES
FOR EACH ROW
BEGIN
    IF :NEW.HISTORY_ID IS NULL THEN
        SELECT SEQ_DMBO_USER_HISTORIES.NEXTVAL INTO :NEW.HISTORY_ID FROM DUAL;
    END IF;

    IF :NEW.ACTION_DATE IS NULL THEN
        :NEW.ACTION_DATE := SYSTIMESTAMP;
    END IF;
END;
/

CREATE INDEX IX_DMBO_USER_HIS_USER_DATE ON DMBO_USER_HISTORIES (USER_ID, ACTION_DATE);
CREATE INDEX IX_DMBO_USER_HIS_ACTION_DATE ON DMBO_USER_HISTORIES (ACTION_TYPE, ACTION_DATE);
CREATE INDEX IX_DMBO_USER_HIS_FUNC_DATE ON DMBO_USER_HISTORIES (FUNCTION_ID, ACTION_DATE);
CREATE INDEX IX_DMBO_USER_HIS_TABLE_DATE ON DMBO_USER_HISTORIES (EDIT_TABLE, ACTION_DATE);


