-- Đồng bộ ROLE_LEVEL nếu DB đã có role từ script cũ
UPDATE DMBO_ROLE SET ROLE_LEVEL = 0 WHERE UPPER(ROLE_CODE) = 'SUPER_ADMIN' AND ROLE_LEVEL <> 0;
