-- ============================================================
-- 9. Grant all functions to SUPER_ADMIN
-- ============================================================
INSERT INTO DMBO_ROLE_FUNC (ROLE_ID, FUNCTION_ID, CREATE_USER)
SELECT R.ROLE_ID, F.FUNCTION_ID, 'SYSTEM'
FROM DMBO_ROLE R
JOIN DMBO_FUNCTION F ON 1 = 1
WHERE UPPER(R.ROLE_CODE) = 'SUPER_ADMIN'
  AND NOT EXISTS (
      SELECT 1
      FROM DMBO_ROLE_FUNC RF
      WHERE RF.ROLE_ID = R.ROLE_ID
        AND RF.FUNCTION_ID = F.FUNCTION_ID
  );


-- ============================================================
-- 10. View: user functions flattening
-- ============================================================
CREATE OR REPLACE VIEW VW_DMBO_USER_FUNCTIONS AS
SELECT
    U.USER_ID,
    U.USER_NAME,
    U.FULL_NAME,
    U.STATUS AS USER_STATUS,
    R.ROLE_ID,
    R.ROLE_CODE,
    R.ROLE_NAME,
    F.FUNCTION_ID,
    F.FUNCTION_CODE,
    F.FUNCTION_NAME,
    F.FUNCTION_LEVEL,
    F.FUNCTION_URL,
    F.FUNCTION_ORDER,
    F.PARENT_ID,
    F.FUNCTION_DISPLAY
FROM DMBO_USER U
JOIN DMBO_ROLE R ON R.ROLE_ID = U.ROLE_ID
JOIN DMBO_ROLE_FUNC RF ON RF.ROLE_ID = R.ROLE_ID
JOIN DMBO_FUNCTION F ON F.FUNCTION_ID = RF.FUNCTION_ID
WHERE U.STATUS = 1
  AND R.STATUS = 'ACTIVE'
  AND F.STATUS = 'ACTIVE';


COMMIT;

